// ExpressServiceServer is the server API for ExpressService service.
// All implementations must embed UnimplementedExpressServiceServer
// for forward compatibility.
//
// 快递服务
type ExpressServiceServer interface {
	// 创建寄件订单（派单 + 生成取件码）
	CreateExpress(context.Context, *CreateExpressRequest) (*CreateExpressReply, error)
	// 我的快递列表（分页）
	ListExpress(context.Context, *ListExpressRequest) (*ListExpressReply, error)
	// 订单详情
	GetExpress(context.Context, *GetExpressRequest) (*GetExpressReply, error)
	// 确认取件（驿站取件）
	PickupExpress(context.Context, *PickupExpressRequest) (*PickupExpressReply, error)
	// 取消订单
	CancelExpress(context.Context, *CancelExpressRequest) (*CancelExpressReply, error)
	// 快递员上门核验（Phase 2 新增）
	VerifyPickup(context.Context, *VerifyPickupRequest) (*VerifyPickupReply, error)
	// 快递员待揽收列表（Phase 2 新增）
	GetCourierPendingOrders(context.Context, *GetCourierPendingOrdersRequest) (*GetCourierPendingOrdersReply, error)
	// 取消超时订单（Phase 2 新增）
	CancelTimeoutOrder(context.Context, *CancelTimeoutOrderRequest) (*CancelTimeoutOrderReply, error)
	// 区域覆盖检查（Phase 2 新增）
	CheckCoverage(context.Context, *CheckCoverageRequest) (*CheckCoverageReply, error)
	// 管理员人工派单（Phase 2 新增）
	ManualAssignOrder(context.Context, *ManualAssignOrderRequest) (*ManualAssignOrderReply, error)
	// 更新订单状态（Phase 3 新增）
	UpdateOrderStatus(context.Context, *UpdateOrderStatusRequest) (*UpdateOrderStatusReply, error)
	// 驿站投递（Phase 3 新增）
	DeliverToStation(context.Context, *DeliverToStationRequest) (*DeliverToStationReply, error)
	// 驿站取件（Phase 3 新增）
	PickupFromStation(context.Context, *PickupFromStationRequest) (*PickupFromStationReply, error)
	// 快递柜投递（Phase 3 新增）
	DeliverToCabinet(context.Context, *DeliverToCabinetRequest) (*DeliverToCabinetReply, error)
	// 快递柜取件（Phase 3 新增）
	PickupFromCabinet(context.Context, *PickupFromCabinetRequest) (*PickupFromCabinetReply, error)
	// 查询物流轨迹（Phase 3 新增）
	GetTrace(context.Context, *GetTraceRequest) (*GetTraceReply, error)
	// 追加轨迹项（Phase 3 新增）
	AppendTrace(context.Context, *AppendTraceRequest) (*AppendTraceReply, error)
	mustEmbedUnimplementedExpressServiceServer()
}

